dialogue.llm_output:
针对微信文章内容抓取的增强方案，主要改进子标题提取和图片抓取功能。以下是优化后的代码：

```python
from flask import Flask, request, render_template
import requests
from bs4 import BeautifulSoup, Tag
from urllib.parse import urlparse, urljoin
import re

app = Flask(__name__)

# 公共请求头
HEADERS = {
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36',
    'Referer': 'https://mp.weixin.qq.com/'
}

def parse_weixin_content(url):
    """增强版内容解析函数"""
    try:
        response = requests.get(url, headers=HEADERS, timeout=15)
        soup = BeautifulSoup(response.text, 'lxml')  # 改用lxml解析器

        # 提取主标题
        title = soup.find('h1', {'id': 'activity-name'}).get_text(strip=True)

        # 作者和发布时间
        author_tag = soup.find('span', class_='rich_media_meta rich_media_meta_text')
        author = author_tag.get_text(strip=True) if author_tag else ''

        date_tag = soup.find('em', id='publish_time')
        publish_date = date_tag.get_text(strip=True) if date_tag else ''

        # 核心内容解析
        content_div = soup.find('div', {'id': 'js_content'})
        elements = []
        image_urls = []

        # 递归解析子元素
        def parse_children(element):
            if not isinstance(element, Tag):
                return

            # 处理图片（优先获取data-src）
            if element.name == 'img':
                img_src = element.get('data-src') or element.get('src')
                if img_src:
                    full_url = urljoin(url, img_src)
                    image_urls.append(full_url)
                    return {'type': 'image', 'content': full_url}

            # 处理子标题（匹配h2标签或特定样式）
            if element.name in ['h2', 'h3'] or 'section_title' in element.get('class', []):
                text = element.get_text(strip=True)
                if text:
                    return {'type': 'subtitle', 'content': text}

            # 处理段落文本
            if element.name == 'p':
                text = element.get_text(strip=True)
                if text and not re.match(r'^var\s', text):  # 过滤JS变量
                    return {'type': 'paragraph', 'content': text}

            # 处理列表
            if element.name in ['ul', 'ol']:
                items = [li.get_text(strip=True) for li in element.find_all('li')]
                return {'type': 'list', 'content': items}

            # 递归处理子元素
            children = []
            for child in element.children:
                parsed = parse_children(child)
                if isinstance(parsed, dict):
                    children.append(parsed)
                elif isinstance(parsed, list):
                    children.extend(parsed)
            return children

        elements = parse_children(content_div) or []

        return {
            'title': title,
            'author': author,
            'publish_date': publish_date,
            'elements': elements,
            'images': image_urls
        }

    except Exception as e:
        print(f"解析内容时出错: {str(e)}")
        return None

# 修改后的路由处理（保持其他函数不变）
@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        url = request.form['url']

        if not is_weixin_url(url):
            return render_template('index.html', error="请输入有效的微信文章URL")

        if not check_url_availability(url):
            return render_template('index.html', error="文章无法访问，可能已被删除或需要登录")

        content = parse_weixin_content(url)
        if not content:
            return render_template('index.html', error="内容解析失败，可能页面结构已更新")

        return render_template('result.html', **content)

    return render_template('index.html')

if __name__ == '__main__':
    app.run(debug=True)
```

